  ('disabled-8b44517b-moex-00098', 'disabled-8b44517b', 'disabled-8b44517b-moex-113-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '有關行政程序法第159條第2項所規定之行政規則類型，下列何者錯誤？', '["行政機關得透過行政規則，訂定一般性之人事管理規定，以利機關內部 組織、事務順利運作", "為收統一與加速行政作業程序之效，行政機關依法就人民須申請許可事 項制定施行細則，亦屬於行政規則", "行政機關為統一所屬公務員或下級機關之法令解釋，得利用行政規則， 就實務上易生爭議之法令予以核釋", "行政機關訂定裁量基準，以協助下級機關或屬官行使裁量權，為行政規則 30830"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00099', 'disabled-8b44517b', 'disabled-8b44517b-moex-113-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '公務員同一行為先受懲處處分後，復移送懲戒時，下列何者正確？', '["如懲戒法院為免議之判決確定者，原懲處處分之效力不受影響", "如懲戒法院為不受懲戒判決確定者，原懲處處分失其效力", "如懲戒法院為申誡懲戒處分之判決者，原懲處處分之效力不受影響", "如懲戒法院為撤職懲戒處分之判決者，應一併宣告撤銷原懲處處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
