  ('disabled-8b44517b-moex-00103', 'disabled-8b44517b', 'disabled-8b44517b-moex-113-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '下列何者為行政事實行為？', '["公園開放使用之公告", "地政機關所為土地移轉登記", "函請受領人繳還因撤銷補貼許可所生溢領金額之通知", "文化部函復內政部移民署某甲不符入境許可條件之通知"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "07ceeac2e0a7", "answer_pdf_sha1": "1fe7fe378049", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL)
